<!DOCTYPE html><html lang="fr"><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1"><title>Cartes Connecte - {{ $ecole->nom ?? 'Ecole' }}</title><link rel="stylesheet" href="{{ asset('legacy/assets/fontawesome/css/all.min.css') }}"><script src="{{ asset('legacy/vendor/qrcode.min.js') }}"></script><style>*{box-sizing:border-box}html,body{margin:0;min-height:100vh;font-family:Inter,system-ui,-apple-system,sans-serif;background:linear-gradient(135deg,#f0f4f8 0%,#e2e8f0 100%);color:#111827}.header{position:sticky;top:0;z-index:100;background:rgba(255,255,255,.92);backdrop-filter:blur(12px);border-bottom:1px solid #e2e8f0;padding:12px 16px;display:flex;align-items:center;gap:10px;flex-wrap:wrap;box-shadow:0 2px 12px rgba(0,0,0,.06)}.header h1{margin:0;font-size:1.1rem;color:#034a3b;display:flex;align-items:center;gap:8px}.header h1 i{font-size:1rem}.filters{display:flex;gap:8px;flex-wrap:wrap;align-items:center;margin-left:auto}.filters select,.filters input{padding:7px 10px;border:1px solid #d1d9e6;border-radius:7px;font-size:.82rem;background:#fff;color:#111;outline:none;min-width:120px}.filters select:focus,.filters input:focus{border-color:#034a3b}.filters button{padding:7px 14px;background:#034a3b;color:#fff;border:0;border-radius:7px;font-weight:700;font-size:.82rem;cursor:pointer}.grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(320px,1fr));gap:18px;padding:18px;max-width:1400px;margin:0 auto}.card{background:#fff;border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(0,0,0,.08);transition:transform .15s,box-shadow .15s;display:flex;flex-direction:column}.card:hover{transform:translateY(-3px);box-shadow:0 8px 30px rgba(0,0,0,.12)}.card-header{background:linear-gradient(135deg,#034a3b,#046a50);padding:14px 16px;display:flex;align-items:center;gap:12px;color:#fff}.card-header .badge{background:rgba(255,255,255,.2);border-radius:5px;padding:3px 10px;font-size:.68rem;font-weight:700;text-transform:uppercase;letter-spacing:.5px}.card-header h3{margin:0;font-size:.95rem;font-weight:700;flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.card-body{display:flex;gap:14px;padding:14px 16px;align-items:center;flex:1}.card-photo{width:64px;height:64px;border-radius:50%;object-fit:cover;background:#f1f5f9;border:3px solid #e2e8f0;flex-shrink:0}.card-meta{flex:1;min-width:0}.card-meta .meta-row{display:flex;align-items:center;gap:6px;font-size:.78rem;color:#475569;margin-bottom:4px}.card-meta .meta-row i{width:14px;color:#034a3b;font-size:.72rem}.card-meta .meta-row span{color:#111;font-weight:600}.card-meta .school-name{display:block;margin-top:6px;font-size:.72rem;color:#94a3b8;font-weight:600;padding-top:6px;border-top:1px solid #e2e8f0}.card-qr{background:#f8fafc;padding:14px;display:flex;justify-content:center;border-top:1px solid #e2e8f0;border-radius:0 0 16px 16px}.card-qr .qr-box{display:grid;place-items:center;width:180px;height:180px;border-radius:8px;background:#fff;padding:6px;box-shadow:0 2px 8px rgba(0,0,0,.06)}.card-qr .qr-box canvas,.card-qr .qr-box img{max-width:100%!important;height:auto!important}.empty{grid-column:1/-1;text-align:center;padding:80px 20px;color:#64748b}.empty i{font-size:3.5rem;display:block;margin-bottom:16px;opacity:.3}.empty p{margin:0;font-size:1.05rem}.empty .sub{font-size:.85rem;margin-top:6px;color:#94a3b8}@media(min-width:768px){.grid{grid-template-columns:repeat(auto-fill,minmax(350px,1fr))}.card-qr img{width:200px;height:200px}}@media(min-width:1024px){.grid{grid-template-columns:repeat(auto-fill,minmax(380px,1fr))}.card-qr img{width:220px;height:220px}}@media print{@page{size:A4 portrait;margin:6mm}*,*::before,*::after{-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important;box-shadow:none!important;text-shadow:none!important}.header{display:none!important}.grid{gap:10px;padding:0}.card{break-inside:avoid!important;page-break-inside:avoid!important;border:1px solid #cbd5e1!important;box-shadow:none!important;border-radius:10px!important}.card-header{background:#034a3b!important;-webkit-print-color-adjust:exact!important;print-color-adjust:exact!important}.card-qr img{width:160px!important;height:160px!important;padding:4px!important}}</style></head><body>
<div class="header"><h1><i class="fa fa-qrcode"></i> {{ $ecole->nom ?? 'Ecole' }} &mdash; Connecte</h1><form class="filters" method="GET"><select name="type" onchange="this.form.submit()"><option value="">Tous</option><option value="etudiant" @selected($selectedType==='etudiant')>Eleves</option><option value="enseignant" @selected($selectedType==='enseignant')>Enseignants</option><option value="staff" @selected($selectedType==='staff')>Staff</option></select>@if($selectedType==='etudiant')<select name="classe" onchange="this.form.submit()"><option value="">Toutes les classes</option>@foreach($classes as $classe)<option value="{{ $classe->id }}" @selected($selectedClasse===$classe->id)>{{ $classe->nom }}</option>@endforeach</select>@endif<input type="text" name="search" placeholder="Rechercher..." value="{{ request('search') }}" onchange="this.form.submit()"><button type="submit"><i class="fa fa-search"></i></button></form></div>
<div class="grid">@forelse($people as $person)@php $photo = $person->photo ?: 'Uploads/default.jpg'; @endphp@php $qrToken = $person->qr_token ?? ''; @endphp<div class="card"><div class="card-header"><span class="badge">{{ $selectedType === 'etudiant' ? ($person->nom_classe ?? 'Eleve') : ucfirst($selectedType) }}</span><h3>{{ $person->nom }} {{ $person->prenom }}</h3></div><div class="card-body"><img class="card-photo" src="{{ asset('legacy/'.ltrim($photo,'/')) }}" alt="" loading="lazy"><div class="card-meta"><div class="meta-row"><i class="fa fa-id-card"></i> ID : <span>{{ $person->matricule ?? $person->id }}</span></div>@if($person->telephone)<div class="meta-row"><i class="fa fa-phone"></i> Tel : <span>{{ $person->telephone }}</span></div>@endif<div class="meta-row"><i class="fa fa-calendar"></i> {{ $selectedType === 'etudiant' ? ($person->annee_scolaire ?? '') : '' }}</div><span class="school-name">{{ $ecole->nom ?? 'Ecole' }}</span></div></div>@if($qrToken)<div class="card-qr"><div class="qr-box" id="cq-{{ $person->id }}" data-qr="novaskol:qr:v1:{{ $qrToken }}"></div></div>@endif</div>@empty<div class="empty"><i class="fa fa-qrcode"></i><p>Aucune carte trouvee.</p><p class="sub">Selectionnez un type et une classe pour afficher les cartes.</p></div>@endforelse</div>
<script>document.addEventListener('DOMContentLoaded',function(){document.querySelectorAll('.card-qr .qr-box').forEach(function(q){var t=q.getAttribute('data-qr')||q.getAttribute('data-url');if(t&&window.QRCode)new QRCode(q,{text:t,width:168,height:168,colorDark:'#07111f',colorLight:'#ffffff',correctLevel:QRCode.CorrectLevel.M})})})</script></body></html>
